106→const resolveCount = (
107→  aggregate: Array<{count?: number}> | undefined,
108→  fallback?: number,
109→): number => {
110→  if (Array.isArray(aggregate) && aggregate.length > 0)
111→    return normalizeCount(aggregate[0]?.count);
112→  return normalizeCount(fallback);
113→};
